423:      * Validates the request.
424:      *
425:      * @param request The request to validate.
426:      * @param apiVersion The version of ConsumerGroupHeartbeat RPC
427:      * @throws InvalidRequestException if the request is not valid.
428:      * @throws UnsupportedAssignorException if the assignor is not supported.
429:      */
430:     private void throwIfConsumerGroupHeartbeatRequestIsInvalid(
431:         ConsumerGroupHeartbeatRequestData request,
432:         int apiVersion
433:     ) throws InvalidRequestException, UnsupportedAssignorException {
434:         if (apiVersion >= CONSUMER_GENERATED_MEMBER_ID_REQUIRED_VERSION ||
435:             request.memberEpoch() > 0 ||
436:             request.memberEpoch() == LEAVE_GROUP_MEMBER_EPOCH
437:         ) {
438:             throwIfEmptyString(request.memberId(), "MemberId can't be empty.");
439:         }
440: 
441:         throwIfEmptyString(request.groupId(), "GroupId can't be empty.");
442:         throwIfEmptyString(request.instanceId(), "InstanceId can't be empty.");
443:         throwIfEmptyString(request.rackId(), "RackId can't be empty.");
444: 
445:         if (request.memberEpoch() == 0) {
446:             if (request.rebalanceTimeoutMs() == -1) {
447:                 throw new InvalidRequestException("RebalanceTimeoutMs must be provided in first request.");
448:             }
449:             if (request.topicPartitions() == null || !request.topicPartitions().isEmpty()) {
450:                 throw new InvalidRequestException("TopicPartitions must be empty when (re-)joining.");
451:             }
452:             // We accept members joining with an empty list of names or an empty regex. It basically
453:             // means that they are not subscribed to any topics, but they are part of the group.
454:             if (request.subscribedTopicNames() == null && request.subscribedTopicRegex() == null) {
455:                 throw new InvalidRequestException("Either SubscribedTopicNames or SubscribedTopicRegex must" +
456:                     " be non-null when (re-)joining.");
457:             }
458:         } else if (request.memberEpoch() == LEAVE_GROUP_STATIC_MEMBER_EPOCH) {
459:             throwIfNull(request.instanceId(), "InstanceId can't be null.");
460:         } else if (request.memberEpoch() < LEAVE_GROUP_STATIC_MEMBER_EPOCH) {
461:             throw new InvalidRequestException("MemberEpoch is invalid.");
462:         }
463: 
464:         if (request.serverAssignor() != null && !consumerGroupAssignors.contains(request.serverAssignor())) {
465:             throw new UnsupportedAssignorException("ServerAssignor " + request.serverAssignor()
466:                 + " is not supported. Supported assignors: " + String.join(", ", consumerGroupAssignors)
467:                 + ".");
468:         }
469:     }
