808:     // Visibility for testing
809:     CompletableFuture<ShareGroupHeartbeatResponseData> persisterInitialize(
810:         InitializeShareGroupStateParameters request,
811:         ShareGroupHeartbeatResponseData defaultResponse
812:     ) {
813:         return persister.initializeState(request)
814:             .handle((response, exp) -> {
815:                 if (exp == null) {
816:                     return handlePersisterInitializeResponse(request.groupTopicPartitionData().groupId(), response, defaultResponse);
817:                 }
818:                 GroupTopicPartitionData<PartitionStateData> gtp = request.groupTopicPartitionData();
819:                 log.error("Unable to initialize share group state {}, {}", gtp.groupId(), gtp.topicsData(), exp);
820:                 Errors error = Errors.forException(exp);
821:                 Map<Uuid, Set<Integer>> topicPartitionMap = new HashMap<>();
822:                 gtp.topicsData().forEach(topicData -> topicPartitionMap.computeIfAbsent(topicData.topicId(), k -> new HashSet<>())
823:                     .addAll(topicData.partitions().stream().map(PartitionStateData::partition).collect(Collectors.toSet())));
824:                 return uninitializeShareGroupState(error, gtp.groupId(), topicPartitionMap);
825:             })
826:             .thenCompose(resp -> resp);
827:     }
