829:     private CompletableFuture<ShareGroupHeartbeatResponseData> handlePersisterInitializeResponse(
830:         String groupId,
831:         InitializeShareGroupStateResult persisterInitializeResult,
832:         ShareGroupHeartbeatResponseData defaultResponse
833:     ) {
834:         Errors persisterError = Errors.NONE;
835:         for (TopicData<PartitionErrorData> topicData : persisterInitializeResult.topicsData()) {
836:             Optional<PartitionErrorData> errData = topicData.partitions().stream().filter(partition -> partition.errorCode() != Errors.NONE.code()).findAny();
837:             if (errData.isPresent()) {
838:                 persisterError = Errors.forCode(errData.get().errorCode());
839:                 break;
840:             }
841:         }
842: 
843:         Map<Uuid, Set<Integer>> topicPartitionMap = new HashMap<>();
844:         for (TopicData<PartitionErrorData> topicData : persisterInitializeResult.topicsData()) {
845:             topicPartitionMap.put(
846:                 topicData.topicId(),
847:                 topicData.partitions().stream().map(PartitionErrorData::partition).collect(Collectors.toSet())
848:             );
849:         }
850: 
851:         if (persisterError.code() == Errors.NONE.code()) {
852:             if (topicPartitionMap.isEmpty()) {
853:                 return CompletableFuture.completedFuture(defaultResponse);
854:             }
855:             return performShareGroupStateMetadataInitialize(groupId, topicPartitionMap, defaultResponse);
856:         }
857:         log.error("Received error while calling initialize state for {} on persister, errorCode: {}.", groupId, persisterError.code());
858:         return uninitializeShareGroupState(persisterError, groupId, topicPartitionMap);
859:     }
860: 
861:     private CompletableFuture<ShareGroupHeartbeatResponseData> uninitializeShareGroupState(
862:         Errors error,
863:         String groupId,
864:         Map<Uuid, Set<Integer>> topicPartitionMap
865:     ) {
866:         return runtime.scheduleWriteOperation(
867:             "uninitialize-share-group-state",
868:             topicPartitionFor(groupId),
869:             coordinator -> coordinator.uninitializeShareGroupState(groupId, topicPartitionMap)
870:         ).thenApply(__ -> new ShareGroupHeartbeatResponseData()
871:             .setErrorCode(error.code())
872:             .setErrorMessage(error.message())
873:         ).exceptionally(exception -> {
874:             log.error("Unable to cleanup topic partitions from share group state metadata", exception);
875:             Errors err = Errors.forException(new IllegalStateException("Unable to cleanup topic partitions from share group state metadata", exception));
876:             return new ShareGroupHeartbeatResponseData()
877:                 .setErrorCode(err.code())
878:                 .setErrorMessage(err.message());
879:         });
880:     }
881: 
882:     private CompletableFuture<ShareGroupHeartbeatResponseData> performShareGroupStateMetadataInitialize(
883:         String groupId,
884:         Map<Uuid, Set<Integer>> topicPartitionMap,
885:         ShareGroupHeartbeatResponseData defaultResponse
886:     ) {
887:         return runtime.scheduleWriteOperation(
888:             "initialize-share-group-state",
889:             topicPartitionFor(groupId),
890:             coordinator -> coordinator.initializeShareGroupState(groupId, topicPartitionMap)
891:         ).handle((__, exp) -> {
892:             if (exp == null) {
893:                 return CompletableFuture.completedFuture(defaultResponse);
894:             }
895:             log.error("Unable to initialize share group state partition metadata for {}.", groupId, exp);
896:             Errors error = Errors.forException(exp);
897:             return uninitializeShareGroupState(error, groupId, topicPartitionMap);
898:         }).thenCompose(resp -> resp);
899:     }
