2257:      * Handles the deletion of topics by scheduling write operations
2258:      * to delete committed offsets and clean up share group state.
2259:      *
2260:      * @param topicsDelta The topics delta containing deleted topic IDs.
2261:      */
2262:     private void handleTopicsDeletion(TopicsDelta topicsDelta) {
2263:         var deletedTopicIds = topicsDelta.deletedTopicIds();
2264:         var deletedTopics = new ArrayList<DeletedTopic>();
2265: 
2266:         deletedTopicIds.forEach(topicId -> {
2267:             var topicImage = topicsDelta.image().getTopic(topicId);
2268:             if (topicImage != null) {
2269:                 deletedTopics.add(new DeletedTopic(topicId, topicImage.name()));
2270:             }
2271:         });
2272: 
2273:         var futures = new ArrayList<CompletableFuture<Void>>();
2274: 
2275:         if (!deletedTopics.isEmpty()) {
2276:             // Schedule offset deletion.
2277:             futures.addAll(
2278:                 FutureUtils.mapExceptionally(
2279:                     runtime.scheduleWriteAllOperation(
2280:                         "on-topics-deleted",
2281:                         coordinator -> coordinator.onTopicsDeleted(deletedTopics)
2282:                     ),
2283:                     exception -> {
2284:                         log.error("Could not delete offsets for deleted topics {} due to: {}.",
2285:                             deletedTopics, exception.getMessage(), exception);
2286:                         return null;
2287:                     }
2288:                 )
2289:             );
2290:         }
2291: 
2292:         if (!deletedTopicIds.isEmpty()) {
2293:             // Schedule share group state cleanup.
2294:             futures.addAll(
2295:                 FutureUtils.mapExceptionally(
2296:                     runtime.scheduleWriteAllOperation(
2297:                         "maybe-cleanup-share-group-state",
2298:                         coordinator -> coordinator.maybeCleanupShareGroupState(deletedTopicIds)
2299:                     ),
2300:                     exception -> {
2301:                         log.error("Unable to cleanup state for the deleted topics {}", deletedTopicIds, exception);
2302:                         return null;
2303:                     }
2304:                 )
2305:             );
2306:         }
2307: 
2308:         // Wait for all operations to complete.
2309:         CompletableFuture.allOf(futures.toArray(new CompletableFuture<?>[0])).join();
2310:     }
