      TopicPartition tp = new TopicPartition(Topic.GROUP_METADATA_TOPIC_NAME, 0);

      CompletableFuture<Void> future = service.completeTransaction(
          tp,
          100L,
          (short) 5,
          1,
          TransactionResult.COMMIT,
          (short) 1
      );

      assertTrue(future.isCompletedExceptionally());
      assertFutureThrows(Errors.COORDINATOR_NOT_AVAILABLE.exception().getClass(), future);
  }
